import face_recognition
from flask import Flask, request, jsonify

app = Flask(__name__)

# Load known images and their corresponding labels
known_images = []
labels = []

for image_path in ['path/to/image1.jpg', 'path/to/image2.jpg']:
    img = face_recognition.load_image_file(image_path)
    encoding = face_recognition.face_encodings(img)[0]
    known_images.append(encoding)
    labels.append('employee1')

# Create a model
model = face_recognition.FaceRecognizer(known_images)

@app.route('/recognize', methods=['POST'])
def recognize():
    # Get the image from the request
    img = request.files['image']
    
    # Encode the faces in the image
    encodings = face_recognition.face_encodings(face_recognition.load_image_file(img))

    if not encodings:
        return jsonify({'error': 'No faces found'})

    # Compare the encoded faces with the known images
    distances, labels = model.compare(encodings)

    # Get the confidence scores for each class
    conf_scores = {}
    for i in range(len(labels)):
        conf_scores[labels[i]] = 1 - (distances[i] ** 2) / (-2 * sum(distances))

    return jsonify(conf_scores)


@app.route('/probabilities', methods=['POST'])
def probabilities():
    # Get the image from the request
    img = request.files['image']
    
    # Encode the faces in the image
    encodings = face_recognition.face_encodings(face_recognition.load_image_file(img))

    if not encodings:
        return jsonify({'error': 'No faces found'})

    # Compare the encoded faces with the known images
    distances, labels = model.compare(encodings)

    # Get the probability distribution over all known faces
    prob_dist = {}
    for i in range(len(labels)):
        prob_dist[labels[i]] = face_recognition.face_distance(known_images, encodings[i])

    return jsonify(prob_dist)


if __name__ == '__main__':
    app.run(debug=True)